#!/usr/bin/env node
/* eslint-env node */
/* Generated by GitHub Copilot
 * Description: Script to run npm audit fix and capture package changes
 * This script performs vulnerability audits and package updates
 */

import { execSync } from 'child_process';
import fs from 'fs';
// path was previously imported but not used; removed to avoid lint warnings


const PROJECT_DIR = '/workspaces/mcp-server-vscode';
process.chdir(PROJECT_DIR);

function runCommand(cmd, description) {
  console.log(`\n${'='.repeat(60)}`);
  console.log(`${description}`);
  console.log('='.repeat(60));
  try {
    const output = execSync(cmd, { encoding: 'utf-8', stdio: 'pipe' });
    console.log(output);
    return output;
  } catch (error) {
    console.log(error.stdout || '');
    console.log(error.stderr || '');
    return error.stdout || '';
  }
}

function readJsonFile(filepath) {
  return JSON.parse(fs.readFileSync(filepath, 'utf-8'));
}

// Step 1: Check current state
runCommand('git branch', 'Current Git Branch');
runCommand('git status', 'Git Status');

// Step 2: Read initial package.json
const pkgBefore = readJsonFile('package.json');
// package-lock is not needed by this script; skip reading it


console.log('\n' + '='.repeat(60));
console.log('BEFORE: Mocha version');
console.log('='.repeat(60));
console.log('mocha:', pkgBefore.devDependencies.mocha);

// Step 3: Create branch
runCommand('git checkout -b fix/npm-audit-vulnerabilities 2>&1 || git checkout fix/npm-audit-vulnerabilities', 'Creating/Switching to fix branch');

// Step 4: Initial audit
const auditBefore = runCommand('npm audit 2>&1', 'Initial npm audit');

// Step 5: Run npm audit fix --force
// run the audit fix; output is already logged inside runCommand
runCommand('npm audit fix --force 2>&1', 'Running npm audit fix --force');

// Step 6: Check updated versions
const pkgAfter = readJsonFile('package.json');
// package-lock after fix is not used in this script, skipping read


console.log('\n' + '='.repeat(60));
console.log('AFTER: Updated versions');
console.log('='.repeat(60));
console.log('mocha:', pkgAfter.devDependencies.mocha);
if (pkgAfter.devDependencies['@types/mocha']) {
  console.log('@types/mocha:', pkgAfter.devDependencies['@types/mocha']);
}

// Step 7: Run tests
const testOutput = runCommand('npm test 2>&1', 'Running npm test');

// Step 8: Run compile
const compileOutput = runCommand('npm run compile 2>&1', 'Running npm run compile');

// Step 9: Final audit
const auditAfter = runCommand('npm audit 2>&1', 'Final npm audit');

// Step 10: Summary
console.log('\n' + '='.repeat(60));
console.log('SUMMARY');
console.log('='.repeat(60));
console.log('Branch created/switched: fix/npm-audit-vulnerabilities');
console.log('\nPackage Changes:');
console.log('  mocha: ' + pkgBefore.devDependencies.mocha + ' -> ' + pkgAfter.devDependencies.mocha);

const testPassed = !testOutput.includes('failing');
const compilePassed = !compileOutput.toLowerCase().includes('error');

console.log('\nTest Status:', testPassed ? 'PASSED' : 'FAILED');
console.log('Compile Status:', compilePassed ? 'PASSED' : 'FAILED');

console.log('\nVulnerability Status:');
console.log('Before:', auditBefore.match(/\d+ vulnerabilities/) ? auditBefore.match(/\d+ vulnerabilities/)[0] : 'Check output above');
console.log('After:', auditAfter.match(/\d+ vulnerabilities/) ? auditAfter.match(/\d+ vulnerabilities/)[0] : 'up to date');
